create table "_Configuration"
(
    "Id"          bigint generated by default as identity
        constraint "_Configuration_pk"
            primary key,
    "CreatedOn"   timestamp with time zone default now()                  not null,
    "UpdatedOn"   timestamp with time zone default now()                  not null,
    "UpdatedBy"   bigint                                                  not null,
    "Name"        varchar(32)                                             not null,
    "Value"       text                                                    not null,
    "Category"    text                     default ''::text               not null,
    "DataFormat"  text                     default '''json''::text'::text not null,
    "Description" text                     default ''::text               not null,
    "Key"         text                     default ''::text               not null,
    "RowId"       bigint                   default 0                      not null
);

alter table "_Configuration"
    owner to bcrpro;

create index "IX__Configuration_Category"
    on "_Configuration" ("Category");

create index "IX__Configuration_DataFormat"
    on "_Configuration" ("DataFormat");

create index "IX__Configuration_Key"
    on "_Configuration" ("Key");

create index "IX__Configuration_RowId"
    on "_Configuration" ("RowId");

grant select on "_Configuration" to dev_read;

